import { request, authRequest } from "./api";
import { Course, UserProgress } from "../types/api.types";

export const coursesService = {
  async getAllCourses(token?: string): Promise<Course[]> {
    try {
      // Если есть токен, используем авторизованный запрос
      if (token) {
        return authRequest("/courses", token);
      }
      // Без токена используем обычный запрос
      return request("/courses");
    } catch (error) {
      console.error("Error fetching courses:", error);
      throw error;
    }
  },

  async getCourseById(courseId: string, token?: string): Promise<Course> {
    try {
      if (token) {
        return authRequest(`/courses/${courseId}`, token);
      }
      return request(`/courses/${courseId}`);
    } catch (error) {
      console.error(`Error fetching course ${courseId}:`, error);
      throw error;
    }
  },

  async getUserCourses(token: string): Promise<string[]> {
    const response = await authRequest<{
      email: string;
      selectedCourses: string[];
    }>("/users/me", token);
    return response.selectedCourses || [];
  },

  async getUserCourseProgress(
    courseId: string,
    token: string,
  ): Promise<UserProgress> {
    return authRequest(`/users/me/progress?courseId=${courseId}`, token);
  },

  async getWorkoutProgress(
    courseId: string,
    workoutId: string,
    token: string,
  ): Promise<{
    workoutId: string;
    workoutCompleted: boolean;
    progressData: number[];
  }> {
    return authRequest(
      `/users/me/progress?courseId=${courseId}&workoutId=${workoutId}`,
      token,
    );
  },

  async addCourseToUser(
    courseId: string,
    token: string,
  ): Promise<{ message: string }> {
    return authRequest("/users/me/courses", token, {
      method: "POST",
      body: JSON.stringify({ courseId }),
    });
  },

  async removeCourseFromUser(
    courseId: string,
    token: string,
  ): Promise<{ message: string }> {
    return authRequest(`/users/me/courses/${courseId}`, token, {
      method: "DELETE",
    });
  },

  async resetCourseProgress(
    courseId: string,
    token: string,
  ): Promise<{ message: string }> {
    return authRequest(`/courses/${courseId}/reset`, token, {
      method: "PATCH",
    });
  },
};
